/*
 * Interrupt Handling System in C
 * Demonstrates IVT structure, ISR registration, and interrupt processing
 */

#include <stdio.h>
#include <stdint.h>
#include <string.h>

/* Define interrupt vector numbers */
#define INT_TIMER 0x20 /* Timer interrupt vector */
#define INT_KEYBOARD 0x21 /* Keyboard interrupt vector */
#define INT_DISK 0x2E /* Disk I/O interrupt vector */
#define MAX_VECTORS 256 /* Maximum 256 interrupt vectors */

/* Processor Status Word structure (simplified) */
typedef struct {
 uint8_t carry_flag : 1;
 uint8_t zero_flag : 1;
 uint8_t sign_flag : 1;
 uint8_t overflow_flag : 1;
 uint8_t interrupt_enable : 1;
 uint8_t reserved : 3;
} PSW_t;

/* CPU Context structure - saved during interrupt */
typedef struct {
 uint16_t pc; /* Program Counter */
 uint16_t ax, bx, cx, dx; /* General purpose registers */
 PSW_t psw; /* Processor Status Word */
} CPU_Context_t;

/* Interrupt Service Routine function pointer type */
typedef void (*ISR_Handler)(void);

/* Interrupt Vector Table - array of ISR addresses */
static ISR_Handler interrupt_vector_table[MAX_VECTORS];

/* Stack for context saving */
#define STACK_SIZE 1024
static uint16_t stack[STACK_SIZE];
static int stack_top = -1;

/* Function prototypes */
void save_context_to_stack(CPU_Context_t *ctx);
void restore_context_from_stack(CPU_Context_t *ctx);
void register_interrupt_vector(uint8_t vector_num, ISR_Handler handler);
void handle_interrupt(uint8_t vector_num);

/* Sample ISR implementations */
void timer_isr(void) {
 printf(" [ISR] Timer: System tick updated\n");
 printf(" [ISR] Timer: Sending EOI to PIC\n");
}

void keyboard_isr(void) {
 printf(" [ISR] Keyboard: Reading scan code from port 0x60\n");
 printf(" [ISR] Keyboard: Key pressed - buffer updated\n");
 printf(" [ISR] Keyboard: Sending EOI to PIC\n");
}

void disk_isr(void) {
 printf(" [ISR] Disk: DMA transfer completed\n");
 printf(" [ISR] Disk: Data available in memory buffer\n");
 printf(" [ISR] Disk: Sending EOI to PIC\n");
}

/* Initialize the Interrupt Vector Table */
void init_ivt(void) {
 memset(interrupt_vector_table, 0, sizeof(interrupt_vector_table));
 printf("[IVT] Interrupt Vector Table initialized\n");
}

/* Register an ISR for a specific interrupt vector */
void register_interrupt_vector(uint8_t vector_num, ISR_Handler handler) {
 if (vector_num < MAX_VECTORS) {
 interrupt_vector_table[vector_num] = handler;
 printf("[IVT] Registered ISR for vector 0x%02X\n", vector_num);
 }
}

/* Push value onto stack */
void push_to_stack(uint16_t value) {
 if (stack_top < STACK_SIZE - 1) {
 stack[++stack_top] = value;
 }
}

/* Pop value from stack */
uint16_t pop_from_stack(void) {
 if (stack_top >= 0) {
 return stack[stack_top--];
 }
 return 0;
}

/* Simulate context saving */
void save_context_to_stack(CPU_Context_t *ctx) {
 /* Save Program Counter */
 push_to_stack(ctx->pc);
 /* Save Processor Status Word */
 push_to_stack(*(uint16_t*)&ctx->psw);
 /* Save general purpose registers */
 push_to_stack(ctx->ax);
 push_to_stack(ctx->bx);
 push_to_stack(ctx->cx);
 push_to_stack(ctx->dx);
 printf("[CPU] Context saved to stack\n");
}

/* Simulate context restoration */
void restore_context_from_stack(CPU_Context_t *ctx) {
 /* Restore general purpose registers */
 ctx->dx = pop_from_stack();
 ctx->cx = pop_from_stack();
 ctx->bx = pop_from_stack();
 ctx->ax = pop_from_stack();
 /* Restore Processor Status Word */
 *(uint16_t*)&ctx->psw = pop_from_stack();
 /* Restore Program Counter */
 ctx->pc = pop_from_stack();
 printf("[CPU] Context restored from stack\n");
}

/* Main interrupt handler - called by CPU when interrupt occurs */
void handle_interrupt(uint8_t vector_num) {
 printf("\n[CPU] Interrupt received - Vector: 0x%02X\n", vector_num);

 /* Check if interrupt is enabled in PSW */
 /* In real hardware, this would check the interrupt enable flag */

 /* Create and save current CPU context */
 CPU_Context_t current_ctx;
 current_ctx.pc = 0x1000 + (vector_num * 10); /* Simulated PC */
 current_ctx.ax = 0;
 current_ctx.bx = 0;
 current_ctx.cx = 0;
 current_ctx.dx = 0;
 current_ctx.psw.interrupt_enable = 1;

 printf("[CPU] Saving PC: 0x%04X, PSW flags\n", current_ctx.pc);
 save_context_to_stack(&current_ctx);

 /* Look up ISR address from Interrupt Vector Table */
 ISR_Handler isr = interrupt_vector_table[vector_num];

 if (isr != NULL) {
 printf("[CPU] Jumping to ISR at address: %p\n", (void*)isr);
 /* Execute the Interrupt Service Routine */
 isr();
 printf("[CPU] ISR returned\n");
 } else {
 printf("[ERROR] No ISR registered for vector 0x%02X!\n", vector_num);
 }

 /* Restore context and return to interrupted program */
 restore_context_from_stack(&current_ctx);
 printf("[CPU] Resuming execution at PC: 0x%04X\n", current_ctx.pc);
}

/* Main function - demonstrate interrupt handling */
int main(void) {
 printf("========================================\n");
 printf(" INTERRUPT HANDLING SYSTEM IN C\n");
 printf("========================================\n\n");

 /* Initialize Interrupt Vector Table */
 init_ivt();

 /* Register Interrupt Service Routines */
 printf("\n--- Registering ISRs ---\n");
 register_interrupt_vector(INT_TIMER, timer_isr);
 register_interrupt_vector(INT_KEYBOARD, keyboard_isr);
 register_interrupt_vector(INT_DISK, disk_isr);

 /* Simulate program execution */
 printf("\n--- Program Execution ---\n");
 printf("Main: Executing instructions...\n");
 printf("Main: Instruction at 0x1000 completed\n");
 printf("Main: Instruction at 0x1002 completed\n");

 /* Simulate hardware interrupt - keyboard */
 printf("\n*** HARDWARE INTERRUPT: Keyboard (IRQ1) ***\n");
 handle_interrupt(INT_KEYBOARD);

 /* Continue program execution */
 printf("Main: Instruction at 0x1004 completed\n");

 /* Simulate hardware interrupt - timer */
 printf("\n*** HARDWARE INTERRUPT: Timer (IRQ0) ***\n");
 handle_interrupt(INT_TIMER);

 printf("\nMain: Instruction at 0x1006 completed\n");
 printf("\n--- Execution Complete ---\n");

 return 0;
}
